```typescript
import { Injectable, Inject } from '@nestjs/common';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import { Cache } from 'cache-manager';

@Injectable()
export class MyService {
  constructor(@Inject(CACHE_MANAGER) private cacheManager: Cache) {}

  async getData(key: string) {
    const cached = await this.cacheManager.get(key);
    if (cached) return cached;

    const data = await this.fetchExpensiveData(key);
    await this.cacheManager.set(key, data, 300_000); // 5 min TTL
    return data;
  }
}
```

Group imports in this order, separated by blank lines:

```typescript
// 1. External/NestJS imports
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../shared/prisma/prisma.service';

// 2. Internal module imports
import { Recommendation } from './interfaces/recommendation.interface';
```

- Prefer named exports over default exports
- Use path aliases from `tsconfig.json` where available

```typescript
describe('<ServiceName>', () => {
  describe('<methodName>', () => {
    it('should <expected behavior> when <condition>', async () => {
      // Arrange
      // Act
      // Assert
    });

    it('should throw <error> when <edge case>', async () => {
      // ...
    });
  });
});
```
